CREATE DATABASE IF NOT EXISTS turismo_cr CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE turismo_cr;
CREATE TABLE users(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100) NOT NULL,email VARCHAR(150) NOT NULL UNIQUE,phone VARCHAR(20),photo VARCHAR(255),password VARCHAR(255) NOT NULL,role ENUM('admin','client') NOT NULL DEFAULT 'client',status TINYINT(1) NOT NULL DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE destinations(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,province VARCHAR(80) NOT NULL,description TEXT NOT NULL,image VARCHAR(500),latitude DECIMAL(10,7),longitude DECIMAL(10,7),status TINYINT(1) DEFAULT 1,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE hotels(id INT AUTO_INCREMENT PRIMARY KEY,destination_id INT NOT NULL,name VARCHAR(150) NOT NULL,category TINYINT NOT NULL,address VARCHAR(255),phone VARCHAR(20),email VARCHAR(150),price_per_night DECIMAL(12,2) NOT NULL CHECK(price_per_night>=0),rooms INT NOT NULL DEFAULT 0,description TEXT,image VARCHAR(500),status TINYINT(1) DEFAULT 1,FOREIGN KEY(destination_id) REFERENCES destinations(id) ON UPDATE CASCADE ON DELETE RESTRICT);
CREATE TABLE activities(id INT AUTO_INCREMENT PRIMARY KEY,destination_id INT NOT NULL,name VARCHAR(150) NOT NULL,type VARCHAR(50) NOT NULL,description TEXT,price DECIMAL(12,2) NOT NULL CHECK(price>=0),duration VARCHAR(50),max_capacity INT NOT NULL,status TINYINT(1) DEFAULT 1,image VARCHAR(500),FOREIGN KEY(destination_id) REFERENCES destinations(id) ON UPDATE CASCADE ON DELETE RESTRICT);
CREATE TABLE reservations(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,hotel_id INT NULL,check_in DATE NOT NULL,check_out DATE NOT NULL,people INT NOT NULL,total DECIMAL(12,2) NOT NULL,status ENUM('pending','confirmed','cancelled','completed') DEFAULT 'pending',notes VARCHAR(500),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id),FOREIGN KEY(hotel_id) REFERENCES hotels(id) ON DELETE SET NULL,CHECK(check_out>check_in),CHECK(people>0));
CREATE TABLE reservation_activities(id INT AUTO_INCREMENT PRIMARY KEY,reservation_id INT NOT NULL,activity_id INT NOT NULL,people INT NOT NULL,subtotal DECIMAL(12,2) NOT NULL,FOREIGN KEY(reservation_id) REFERENCES reservations(id) ON DELETE CASCADE,FOREIGN KEY(activity_id) REFERENCES activities(id) ON DELETE RESTRICT,UNIQUE(reservation_id,activity_id));
CREATE TABLE favorites(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NOT NULL,destination_id INT NOT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE,FOREIGN KEY(destination_id) REFERENCES destinations(id) ON DELETE CASCADE,UNIQUE(user_id,destination_id));
CREATE TABLE audit_log(id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,action VARCHAR(120) NOT NULL,details VARCHAR(500),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE SET NULL);
